/**
 * سكريبت إعادة هيكلة فولدر قسم الاحتياجات
 * 
 * طريقة الاستخدام:
 * 1. افتح script.google.com
 * 2. انسخ الكود ده والصقه
 * 3. اضغط Save
 * 4. اضغط Run على دالة main()
 * 5. اديه صلاحية الوصول للدرايف لما يطلب
 */

// ============================================================
// ID الفولدر الرئيسي (قسم الاحتياجات)
// ============================================================
const ROOT_FOLDER_ID = "16oju2ceHzi87QSjDqJxNqAeVmYBbgcSX";

// ============================================================
// IDs الفولدرات الموجودة
// ============================================================
const EXISTING = {
  ALDAR:          "1yg96p_TeeaGOHOBUQAJe3QAQBLBVP4fT",
  ALSAKNA:        "1O-c4NKA6jtKYh6PqKKhKaiP_eVIA1DBm",
  ALHADIKA:       "1R8dLWnjnE1vOrhoyWeGZqi22oHavIssa",
  ALFAWATEER:     "1RJR1ni1rU2TjF80JcKL97ndPsfW1sQof",
  ALSARFIYAT:     "1f9DvUui4EaElxVsqAggdYwdCnIJvG9yJ",
  ALTAHWILAT:     "14kw0RYwTeiMs-fqo99dJblAYRg816H_G",
  ALMUQAYASAT:    "1nkmWxJoHD-dRp1e4T1oevA5zsYwMcGTt",
  ALMUMARASAT:    "1TesYK_vCOPx9IubJtGiq3BANTzpvPDfV",
  ALTAMAMAT:      "1hh7v_iHG3Xqu6mMUwoVt7DB_7wqpAiBv",
  ALSHARIKAT:     "1fQBawCt_Dh-nEl70J9mdgmpNJAuxXULa",
  ALFAKSAAT:      "1XLUT-_Nq-UTI5IAW3Ej2qQKVH4cO1TVv",
  ALTASDIQAT:     "1EWX5Xu29HxX5QfAg6_ijczaGVjNlQ8QL",

  // ملفات في الروت
  FILE_KHOTAT:    "10gy8AfRWyYzLakUKb69si-VtRJbKujw0",
  FILE_HESABAT:   "1bMq07BgBKa9xZJcmdvee2j3BS4A5c5Jx",
  FILE_QAIMA:     "1cU__1C1xChIuhdJ8ybNjI04_WRgPrQhL",
  FILE_MOQARNA:   "1oMliD7sqRAt22P5lo_b-ert8qp5gSw7Z",

  // ملف مكرر في الفاكسات
  FILE_FAX_COPY:  "1IHV1JqavXU-2JcG9plRavBbvuuXhUaHZ",

  // فولدر ايفر كلين المكرر
  EVERCLEN_DUP:   "10q3F1a66rDUJkt1b3WS_WDbq5NkD1zMD",

  // ملف بدون اسم في الشركات
  FILE_NO_NAME:   "11taTasiix6bbH5f8ag4qkc9XJIarAB4-",

  // ملفات ممارسات بأسماء مش واضحة
  FILE_MUMARASA_1: "18lfTEaB00U2WRzxfqw94IJloIwi0LFlM",
  FILE_MUMARASA_2: "1sUidDmRt3hnvbPU7OkgJXfxffdFxxZAO",

  // ملف صرفية في الروت
  FILE_SARFIYA_SHEET5: "1JCljaBhsBIwMiC2sXar60Xr4apjsBYHy",
};

// ============================================================
// الدالة الرئيسية
// ============================================================
function main() {
  const root = DriveApp.getFolderById(ROOT_FOLDER_ID);
  Logger.log("✅ بدأ التنظيم...");

  // 1. إنشاء الفولدرات الجديدة
  Logger.log("📁 جاري إنشاء الهيكل الجديد...");
  const f01_mawaqe3    = getOrCreate(root, "01 - المواقع");
  const f02_sharikat   = getOrCreate(root, "02 - الشركات");
  const f03_maliya     = getOrCreate(root, "03 - المالية");
  const f04_3uqud      = getOrCreate(root, "04 - العقود والمشتريات");
  const f05_morasalat  = getOrCreate(root, "05 - المراسلات والتعاميم");
  const f06_tasdiqat   = getOrCreate(root, "06 - التصاديق الأمنية");
  const f07_maraje3    = getOrCreate(root, "07 - مراجع ولوائح");

  // 2. نقل فولدرات المواقع
  Logger.log("📍 نقل المواقع...");
  moveFolder(EXISTING.ALDAR,    f01_mawaqe3);
  moveFolder(EXISTING.ALSAKNA,  f01_mawaqe3);
  moveFolder(EXISTING.ALHADIKA, f01_mawaqe3);

  // 3. نقل فولدر الشركات
  Logger.log("🏢 نقل الشركات...");
  moveFolder(EXISTING.ALSHARIKAT, f02_sharikat);

  // 4. نقل المالية
  Logger.log("💰 نقل المالية...");
  moveFolder(EXISTING.ALFAWATEER,  f03_maliya);
  moveFolder(EXISTING.ALSARFIYAT,  f03_maliya);
  moveFolder(EXISTING.ALTAHWILAT,  f03_maliya);

  // نقل ملف الصرفية المباشر لجوا فولدر الصرفيات
  moveFile(EXISTING.FILE_SARFIYA_SHEET5, DriveApp.getFolderById(EXISTING.ALSARFIYAT));

  // 5. نقل العقود والمشتريات
  Logger.log("📋 نقل العقود والمشتريات...");
  moveFolder(EXISTING.ALMUQAYASAT, f04_3uqud);
  moveFolder(EXISTING.ALMUMARASAT, f04_3uqud);
  moveFolder(EXISTING.ALTAMAMAT,   f04_3uqud);

  // 6. نقل المراسلات
  Logger.log("📠 نقل المراسلات...");
  moveFolder(EXISTING.ALFAKSAAT, f05_morasalat);

  // 7. نقل التصاديق الأمنية
  Logger.log("🔒 نقل التصاديق الأمنية...");
  moveFolder(EXISTING.ALTASDIQAT, f06_tasdiqat);

  // 8. نقل ملفات المراجع
  Logger.log("📚 نقل ملفات المراجع...");
  moveFile(EXISTING.FILE_KHOTAT,  f07_maraje3);
  moveFile(EXISTING.FILE_HESABAT, f07_maraje3);
  moveFile(EXISTING.FILE_QAIMA,   f07_maraje3);
  moveFile(EXISTING.FILE_MOQARNA, f04_3uqud); // مقارنة أسعار → عقود ومشتريات

  // 9. حذف الملفات المكررة والمش محتاجها
  Logger.log("🗑️ حذف الملفات المكررة...");
  trashFile(EXISTING.FILE_FAX_COPY);  // Copy of فاكس - مكرر

  Logger.log("✅ تم التنظيم بنجاح!");
  Logger.log("⚠️ ملاحظة: فولدر 'ايفر كلين' المكرر وملف بدون اسم وملفات ممارسة/ممارسه ٢ - راجعهم يدوياً قبل الحذف.");
}

// ============================================================
// دوال مساعدة
// ============================================================

function getOrCreate(parentFolder, name) {
  const existing = parentFolder.getFoldersByName(name);
  if (existing.hasNext()) {
    Logger.log("  موجود: " + name);
    return existing.next();
  }
  Logger.log("  إنشاء: " + name);
  return parentFolder.createFolder(name);
}

function moveFolder(folderId, newParent) {
  try {
    const folder = DriveApp.getFolderById(folderId);
    const oldParents = folder.getParents();
    folder.moveTo(newParent);
    Logger.log("  ✅ نقل فولدر: " + folder.getName());
  } catch(e) {
    Logger.log("  ❌ خطأ في نقل الفولدر " + folderId + ": " + e.message);
  }
}

function moveFile(fileId, newParent) {
  try {
    const file = DriveApp.getFileById(fileId);
    file.moveTo(newParent);
    Logger.log("  ✅ نقل ملف: " + file.getName());
  } catch(e) {
    Logger.log("  ❌ خطأ في نقل الملف " + fileId + ": " + e.message);
  }
}

function trashFile(fileId) {
  try {
    const file = DriveApp.getFileById(fileId);
    file.setTrashed(true);
    Logger.log("  🗑️ حذف: " + file.getName());
  } catch(e) {
    Logger.log("  ❌ خطأ في الحذف " + fileId + ": " + e.message);
  }
}
